import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Tooltip,
  Legend
} from "chart.js";
import { Bar } from "react-chartjs-2";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Tooltip,
  Legend
);

function Analytics({ analytics }) {
  const data = {
    labels: analytics.map((d) => d.date),
    datasets: [
      {
        label: "Sales (₹)",
        data: analytics.map((d) => d.sales),
        backgroundColor: "#4f46e5"
      },
      {
        label: "Profit / Loss (₹)",
        data: analytics.map((d) => d.profit),
        borderColor: "#16a34a",
        backgroundColor: "#16a34a",
        type: "line"
      }
    ]
  };

  return (
    <>
      <h3>📈 Sales & Profit Analysis</h3>
      <Bar data={data} />
    </>
  );
}

export default Analytics;
